function validate(args, output) {
    const n = args[0];
    if (n % 2 === 0) return Array.isArray(output) && output.length === 0;
    function deser(a) {
        if (!a || a.length === 0) return null;
        const nodes = [[a[0], null, null]];
        let idx = 1, i = 0;
        while (i < nodes.length && idx < a.length) {
            const node = nodes[i];
            if (idx < a.length) { const v = a[idx]; idx++; if (v !== null) { node[1] = nodes.length; nodes.push([v, null, null]); } }
            if (idx < a.length) { const v = a[idx]; idx++; if (v !== null) { node[2] = nodes.length; nodes.push([v, null, null]); } }
            i++;
        }
        return nodes;
    }
    function checkFull(nodes, i) {
        if (i === null) return [0, true];
        const [val, l, r] = nodes[i];
        if (val !== 0) return [0, false];
        if ((l === null) !== (r === null)) return [0, false];
        const [cl, okL] = checkFull(nodes, l);
        const [cr, okR] = checkFull(nodes, r);
        return [1 + cl + cr, okL && okR];
    }
    function canon(nodes, i) {
        if (i === null) return '#';
        const [val, l, r] = nodes[i];
        return '(' + canon(nodes, l) + ',' + canon(nodes, r) + ')';
    }
    const seen = new Set();
    for (const tw of output) {
        const nodes = deser(tw);
        if (nodes === null) return false;
        const [cnt, ok] = checkFull(nodes, 0);
        if (!ok || cnt !== n) return false;
        const key = canon(nodes, 0);
        if (seen.has(key)) return false;
        seen.add(key);
    }
    const k = Math.floor((n - 1) / 2);
    const catalan = new Array(k + 1).fill(1);
    for (let i = 1; i <= k; i++) {
        let c = 0;
        for (let j = 0; j < i; j++) c += catalan[j] * catalan[i - 1 - j];
        catalan[i] = c;
    }
    return seen.size === catalan[k];
}

