    def allPossibleFBT(self, n):
        if n % 2 == 0:
            return []
        def canon(node):
            if node is None:
                return '#'
            return '(' + canon(node.left) + ',' + canon(node.right) + ')'
        dp = [None] * (n + 1)
        dp[1] = [TreeNode(0)]
        for m in range(3, n + 1, 2):
            res = []
            right_size = 1
            while right_size <= m - 2:
                left_size = m - 1 - right_size
                for r in dp[right_size]:
                    for l in dp[left_size]:
                        node = TreeNode(0)
                        node.left = l
                        node.right = r
                        res.append(node)
                right_size += 2
            res.sort(key=canon)
            dp[m] = res
        return dp[n]

