class Solution:
    def allPossibleFBT(self, n):
        if n % 2 == 0:
            return []
        memo = {}
        def canon(node):
            if node is None:
                return '#'
            return '(' + canon(node.left) + ',' + canon(node.right) + ')'
        def build(m):
            if m in memo:
                return memo[m]
            if m == 1:
                memo[m] = [TreeNode(0)]
                return memo[m]
            res = []
            for left_size in range(1, m - 1, 2):
                right_size = m - 1 - left_size
                for l in build(left_size):
                    for r in build(right_size):
                        node = TreeNode(0)
                        node.left = l
                        node.right = r
                        res.append(node)
            res.sort(key=canon)
            memo[m] = res
            return res
        return build(n)

