var allPossibleFBT = function(n) {
    if (n % 2 === 0) return [];
    const memo = new Map();
    function canon(node) {
        if (node === null) return '#';
        return '(' + canon(node.left) + ',' + canon(node.right) + ')';
    }
    function build(m) {
        if (memo.has(m)) return memo.get(m);
        if (m === 1) {
            const res = [new TreeNode(0)];
            memo.set(m, res);
            return res;
        }
        const res = [];
        for (let leftSize = 1; leftSize <= m - 2; leftSize += 2) {
            const rightSize = m - 1 - leftSize;
            for (const l of build(leftSize)) {
                for (const r of build(rightSize)) {
                    const node = new TreeNode(0);
                    node.left = l;
                    node.right = r;
                    res.push(node);
                }
            }
        }
        res.sort((a, b) => {
            const ka = canon(a), kb = canon(b);
            return ka < kb ? -1 : (ka > kb ? 1 : 0);
        });
        memo.set(m, res);
        return res;
    }
    return build(n);
};
